#include <bits/stdc++.h>
using namespace std;
const int N=105;
int n,t,k;
int a[N],b[N],dp[2005],ans;
int main()
{
    cin>>n>>t>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i]>>b[i];
        for(int j=b[i];j<=t*5/4;j++)
        {
            dp[j]=max(dp[j],dp[j-b[i]]+a[i]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(b[i]>=k) ans=max(ans,dp[(t-b[i])*5/4]+a[i]);
    }
    cout<<max(ans,dp[t]);
    return 0;
}
